+        let count = 1; // Always include self-vote
+        const validGrantedIds = [];
+        for (const voterId of this._grantedVotes) {
+            const record = this._voteRegistry.get(voterId);
+            // Only count votes explicitly granted for the current election term
+            if (record && record.term === currentTerm) {
+                count++;
